-- WCTA CyberPatriot Dashboard — D1 schema + historical seed data
-- Run once in the D1 console. Safe to re-run (drops and rebuilds).

DROP TABLE IF EXISTS scores;
DROP TABLE IF EXISTS rounds_meta;

CREATE TABLE rounds_meta (
  season TEXT NOT NULL,
  round  TEXT NOT NULL,
  teams_nationwide INTEGER,
  date TEXT,
  PRIMARY KEY (season, round)
);

CREATE TABLE scores (
  season TEXT NOT NULL,
  round  TEXT NOT NULL,
  number TEXT,
  name   TEXT NOT NULL,
  linux REAL, win_desktop REAL, win_server REAL,
  packet_quiz REAL, packet_image REAL, packet_total REAL,
  adjust REAL, total REAL,
  nv_rank REAL, natl_rank REAL, natl_pct REAL,
  tier TEXT, adv TEXT,
  cisco_score REAL, boeing_score REAL, web_score REAL, img_score REAL
);
CREATE INDEX idx_scores_sr ON scores(season, round);

